use std::collections::HashMap;

#[repr(C)]
pub struct Foo {
    _hash: [u8; 0x30],
    _map: HashMap<u64, u64>,
    flag: bool,
}

pub fn hashmap_index_key(map_ptr: &Foo, key: u64, early_exit_flag: i8) -> u64 {
    if (map_ptr.flag as i8) == early_exit_flag {
        return key;
    }
    map_ptr._map[&key]
}
